args.query:
SELECT Id, OpportunityId__c, LeadId__c, Body__c, CreatedDate
FROM VoiceCallTranscript__c
WHERE trim(replace(OpportunityId__c,'#','')) IN (
    SELECT trim(replace(Id,'#','')) FROM Opportunity WHERE ContactId IN (
        SELECT ConvertedContactId FROM Lead WHERE trim(replace(Id,'#',''))='00QWt0000089AekMAE'
    )
)
ORDER BY CreatedDate DESC
LIMIT 20;

